import type {
  LedgerEntryDto,
  LedgerReportChartDataDto,
  LedgerReportSummaryDto,
  ReportChartOptionDto,
} from '../../services/kt/models';
import type { LedgerChartData } from './buildLedgerChartData';

const DONUT_COLORS = { debit: '#1677ff', credit: '#fa8c16' } as const;

/** Map BE chart aggregate → FE `LedgerChartData` (full period, not current page). */
export function mapLedgerReportChartDataFromApi(dto: LedgerReportChartDataDto): LedgerChartData {
  const balanceSeries = dto.balanceSeries.map(p => ({
    label: p.label,
    balance: p.balance,
    debit: p.debit,
    credit: p.credit,
  }));

  const dailySeries = dto.dailySeries.map(p => ({
    label: p.label,
    debit: p.debit,
    credit: p.credit,
  }));

  return {
    balanceSeries,
    dailySeries,
    donutSeries: [
      { name: 'PS Nợ', value: dto.totalDebit, fill: DONUT_COLORS.debit },
      { name: 'PS Có', value: dto.totalCredit, fill: DONUT_COLORS.credit },
    ],
    summary: {
      totalDebit: dto.totalDebit,
      totalCredit: dto.totalCredit,
      closingBalance: dto.closingBalance,
      entryCount: dto.entryCount,
    },
  };
}

export function mapLedgerSummaryToChartSummary(summary: LedgerReportSummaryDto): LedgerChartData['summary'] {
  return {
    totalDebit: summary.totalDebit,
    totalCredit: summary.totalCredit,
    closingBalance: summary.closingBalance,
    entryCount: summary.entryCount,
  };
}

export type LedgerReportLoadResult = {
  items: LedgerEntryDto[];
  charts: ReportChartOptionDto[];
  summary: LedgerReportSummaryDto;
  chartData: LedgerChartData | null;
  totalCount: number;
  page: number;
  pageSize: number;
};

export function normalizeLedgerReportResponse(data: {
  items?: LedgerEntryDto[];
  charts?: ReportChartOptionDto[];
  summary?: LedgerReportSummaryDto;
  chartData?: LedgerReportChartDataDto | null;
  totalCount?: number;
  page?: number;
  pageSize?: number;
}): LedgerReportLoadResult {
  const items = Array.isArray(data.items) ? data.items : [];
  const charts = Array.isArray(data.charts) ? data.charts : [];
  const summary = data.summary ?? {
    totalDebit: 0,
    totalCredit: 0,
    closingBalance: 0,
    entryCount: items.length,
  };
  const chartData = data.chartData
    ? mapLedgerReportChartDataFromApi(data.chartData)
    : null;

  return {
    items,
    charts,
    summary,
    chartData,
    totalCount: data.totalCount ?? summary.entryCount,
    page: data.page ?? 1,
    pageSize: data.pageSize ?? items.length,
  };
}
