import React, { useMemo, useState } from 'react';
import classNames from 'classnames';
import { Button, Modal } from '@linm-soft/common-components';
import type { LedgerChartData } from './buildLedgerChartData';
import type { LedgerEntryDto, ReportChartOptionDto } from '../../services/kt/models';
import { formatVnd } from '../../utils/formatters';
import type { ReportPrintFilterLine } from './ReportPrintSummary';
import {
  buildLedgerChartData,
  normalizeReportChartKind,
} from './buildLedgerChartData';
import { LedgerChartView } from './LedgerChartView';
import styles from './LedgerReportChartModal.module.css';

export type LedgerReportChartModalLabels = {
  title: string;
  kpiTotalDebit: string;
  kpiTotalCredit: string;
  kpiClosingBalance: string;
  kpiEntryCount: string;
  seriesDebit: string;
  seriesCredit: string;
  seriesBalance: string;
  viewFull: string;
  empty: string;
  noCharts: string;
};

export type LedgerReportChartModalProps = {
  isOpen: boolean;
  onClose: () => void;
  items: LedgerEntryDto[];
  allowedCharts: ReportChartOptionDto[];
  filterLines: ReportPrintFilterLine[];
  labels: LedgerReportChartModalLabels;
  testIdPrefix: string;
  /** BE aggregate for full filter period — preferred when report is paged. */
  chartData?: LedgerChartData;
  /** From report display config — default true. */
  showKpiStrip?: boolean;
};

type ResolvedChart = ReportChartOptionDto & { kind: 'line' | 'bar' | 'donut' };

function filterSubtitle(lines: ReportPrintFilterLine[]): string {
  return lines.map(l => `${l.label}: ${l.value}`).join(' · ');
}

function resolveCharts(options: ReportChartOptionDto[]): ResolvedChart[] {
  return options
    .map(opt => {
      const kind = normalizeReportChartKind(opt.kind);
      if (!kind) return null;
      return { ...opt, kind };
    })
    .filter((c): c is ResolvedChart => c != null);
}

const PREVIEW_HEIGHT = 260;
const FULL_HEIGHT = 480;

export const LedgerReportChartModal: React.FC<LedgerReportChartModalProps> = ({
  isOpen,
  onClose,
  items,
  allowedCharts,
  filterLines,
  labels,
  testIdPrefix,
  chartData: chartDataProp,
  showKpiStrip = true,
}) => {
  const [fullChart, setFullChart] = useState<ResolvedChart | null>(null);
  const chartData = useMemo(
    () => chartDataProp ?? buildLedgerChartData(items),
    [chartDataProp, items],
  );
  const charts = useMemo(() => resolveCharts(allowedCharts), [allowedCharts]);
  const subtitle = filterSubtitle(filterLines);
  const hasChartData = chartData.summary.entryCount > 0;

  const chartViewLabels = useMemo(
    () => ({
      seriesDebit: labels.seriesDebit,
      seriesCredit: labels.seriesCredit,
      seriesBalance: labels.seriesBalance,
    }),
    [labels.seriesDebit, labels.seriesCredit, labels.seriesBalance],
  );

  const handleClose = () => {
    setFullChart(null);
    onClose();
  };

  return (
    <>
      <Modal
        isOpen={isOpen}
        onClose={handleClose}
        title={labels.title}
        size="lg"
        fillContent
        data-testid={`${testIdPrefix}-chart-modal`}
      >
        {subtitle ? (
          <p className={styles.subtitle} data-testid={`${testIdPrefix}-chart-subtitle`}>
            {subtitle}
          </p>
        ) : null}

        {!hasChartData ? (
          <div className={styles.empty} data-testid={`${testIdPrefix}-chart-empty`}>
            {labels.empty}
          </div>
        ) : charts.length === 0 ? (
          <div className={styles.empty} data-testid={`${testIdPrefix}-chart-no-types`}>
            {labels.noCharts}
          </div>
        ) : (
          <>
            {showKpiStrip ? (
            <div className={styles.kpiGrid} data-testid={`${testIdPrefix}-chart-kpi`}>
              <div className={styles.kpiCard}>
                <div className={styles.kpiLabel}>{labels.kpiTotalDebit}</div>
                <div className={styles.kpiValue}>{formatVnd(chartData.summary.totalDebit)}</div>
              </div>
              <div className={styles.kpiCard}>
                <div className={styles.kpiLabel}>{labels.kpiTotalCredit}</div>
                <div className={styles.kpiValue}>{formatVnd(chartData.summary.totalCredit)}</div>
              </div>
              <div className={styles.kpiCard}>
                <div className={styles.kpiLabel}>{labels.kpiClosingBalance}</div>
                <div className={styles.kpiValue}>{formatVnd(chartData.summary.closingBalance)}</div>
              </div>
              <div className={styles.kpiCard}>
                <div className={styles.kpiLabel}>{labels.kpiEntryCount}</div>
                <div className={styles.kpiValue}>{chartData.summary.entryCount}</div>
              </div>
            </div>
            ) : null}

            <div className={styles.chartBodyScroll}>
            <div className={styles.chartGrid}>
              {charts.map(chart => (
                <div
                  key={chart.chartId}
                  className={classNames(styles.chartCard, chart.kind === 'line' && styles.chartCardFull)}
                  data-testid={`${testIdPrefix}-chart-${chart.chartId}`}
                >
                  <div className={styles.chartCardHeader}>
                    <h4 className={styles.chartTitle}>{chart.title}</h4>
                    {chart.allowViewFull ? (
                      <Button
                        variant="secondary"
                        size="sm"
                        onClick={() => setFullChart(chart)}
                        data-testid={`${testIdPrefix}-chart-${chart.chartId}-view-full`}
                      >
                        {labels.viewFull}
                      </Button>
                    ) : null}
                  </div>
                  <LedgerChartView
                    kind={chart.kind}
                    chartId={chart.chartId}
                    chartData={chartData}
                    labels={chartViewLabels}
                    height={PREVIEW_HEIGHT}
                    testId={`${testIdPrefix}-chart-${chart.chartId}-canvas`}
                  />
                </div>
              ))}
            </div>
            </div>
          </>
        )}
      </Modal>

      <Modal
        isOpen={fullChart != null}
        onClose={() => setFullChart(null)}
        title={fullChart?.title ?? labels.title}
        size="lg"
        fillContent
        stacked
        data-testid={`${testIdPrefix}-chart-full-modal`}
      >
        {fullChart ? (
          <LedgerChartView
            kind={fullChart.kind}
            chartId={fullChart.chartId}
            chartData={chartData}
            labels={chartViewLabels}
            height={FULL_HEIGHT}
            testId={`${testIdPrefix}-chart-${fullChart.chartId}-full-canvas`}
          />
        ) : null}
      </Modal>
    </>
  );
};
