import type { Dispatch, SetStateAction } from 'react';

/** Report filter client validation — Pattern A (erp-form-context §8.1 · §8.2). */

export type ReportFilterFieldRef = {
  /** stateKey in fieldErrors map */
  errorKey: string;
  /** `{testIdPrefix}-field-{fieldSuffix}` */
  fieldSuffix: string;
};

export function patchReportFilterFieldError<T extends Record<string, string | undefined>>(
  setErrors: Dispatch<SetStateAction<T>>,
  key: keyof T & string,
): void {
  setErrors(prev => {
    if (!(key in prev)) return prev;
    const next = { ...prev };
    delete next[key];
    return next;
  });
}

export function scrollToFirstReportFilterField(
  testIdPrefix: string,
  fields: readonly ReportFilterFieldRef[],
  errors: Record<string, string | undefined>,
  delayMs = 120,
): void {
  const first = fields.find(f => errors[f.errorKey]);
  if (!first) return;
  const testId = `${testIdPrefix}-field-${first.fieldSuffix}`;
  setTimeout(() => {
    document.querySelector(`[data-testid="${testId}"]`)?.scrollIntoView({
      behavior: 'smooth',
      block: 'center',
    });
  }, delayMs);
}

export function validateRequiredTrimmed(
  value: string | undefined | null,
  message: string,
): string | undefined {
  return value?.trim() ? undefined : message;
}
